from dataclasses import dataclass

@dataclass
class Triple:
    subject: str
    predicate: str
    object: str

# EVOLVE-BLOCK-START

def predict(triples: list[Triple]) -> str:
    subject_map = {}
    for triple in triples:
        if triple.subject not in subject_map:
            subject_map[triple.subject] = []
        subject_map[triple.subject].append((triple.predicate, triple.object))

    sentence = ""
    for subject, triples_list in subject_map.items():
        if sentence:
            sentence += " which "
        else:
            sentence += f"{subject} "

        predicates = []
        for i, (predicate, obj) in enumerate(triples_list):
            if predicate == "cityServed":
                predicates.append(f"which serves the city of {obj}")
            elif predicate == "mayor":
                predicates.append(f"with a mayor of {obj}")
            elif predicate == "isPartOf":
                predicates.append(f"which is part of {obj}")
            elif predicate == "operatingOrganisation":
                predicates.append(f"operated by {obj}")
            elif predicate == "location":
                predicates.append(f"located in {obj}")
            elif predicate == "elevationAboveTheSeaLevel":
                predicates.append(f"at an elevation of {obj} metres above sea level")
            elif predicate == "runwayLength":
                predicates.append(f"with a runway length of {obj} metres")
            elif predicate == "country":
                predicates.append(f"in the country of {obj}")
            elif predicate == "capital":
                predicates.append(f"whose capital is {obj}")
            elif predicate == "language":
                predicates.append(f"where {obj} is spoken")
            elif predicate == "leader":
                predicates.append(f"led by {obj}")
            elif predicate == "owner":
                predicates.append(f"owned by {obj}")
            elif predicate == "1stRunwayLengthFeet":
                predicates.append(f"with a first runway length of {obj} feet")
            elif predicate == "1stRunwaySurfaceType":
                predicates.append(f"and a first runway with {obj} surface")
            elif predicate == "3rdRunwayLengthFeet":
                predicates.append(f"and a third runway length of {obj} feet")
            elif predicate == "icaoLocationIdentifier":
                predicates.append(f"identified by the ICAO code {obj}")
            elif predicate == "locationIdentifier":
                predicates.append(f"with the location identifier {obj}")
            elif predicate == "elevationAboveTheSeaLevelInFeet":
                predicates.append(f"at an elevation of {obj} feet above sea level")
            elif predicate == "iataLocationIdentifier":
                predicates.append(f"with the IATA code {obj}")
            elif predicate == "nativeName":
                predicates.append(f"also known as {obj}")
            elif predicate == "leaderParty":
                predicates.append(f"with a leader from the {obj} party")
            elif predicate == "runwayName":
                predicates.append(f"featuring a runway named {obj}")
            elif predicate == "runwaySurfaceType":
                predicates.append(f"with a runway surface type of {obj}")
            elif predicate == "elevationAboveTheSeaLevelInMetres":
                predicates.append(f"at an elevation of {obj} metres above sea level")
            elif predicate == "runwayLength":
                predicates.append(f"with a runway length of {obj} metres")
            else:
                predicates.append(f"with a {predicate} of {obj}")

        if predicates:
            sentence += ", ".join(predicates)

    return sentence + "."

